//B. Difference of GCDs #include<bits/stdc++.h>using namespace std;#define int long long intsigned main(){    int t;    cin>>t;    while(t--){        int n,l,r;        cin>>n>>l>>r;        vector<int>arr;        int check=0;        for(int i=1;i<=n;i++){            int a=((l+i-1)/i)*i;            arr.push_back(a);            if(a>r){                check=1;                break;            }        }        if(check==0){            cout<<"YES"<<endl;            for(int i=0;i<n;i++){                cout<<arr[i]<<" ";            }            cout<<endl;        }        else{            cout<<"NO"<<endl;        }    }}